9685 std::optional<bool> llvm::isImpliedByDomCondition(const Value *Cond,
9686                                                   const Instruction *ContextI,
9687                                                   const DataLayout &DL) {
9688   assert(Cond->getType()->isIntOrIntVectorTy(1) && "Condition must be bool");
9689   auto PredCond = getDomPredecessorCondition(ContextI);
9690   if (PredCond.first)
9691     return isImpliedCondition(PredCond.first, Cond, DL, PredCond.second);
9692   return std::nullopt;
